//NS, DLT ,11/03/2025  UOM we required along with MT & LBS, KGS AT closing Stock level
/// <summary>
/// This method used to based on enablesmall point fetch the report and disply the UOM values.
/// </summary>
/// <param name = "_args"></param>
public static void main(Args _args)
{
    ETGClosingStockValueController controller = new ETGClosingStockValueController();

    if (ETGACFParameters::find().EnableClosingStockValueReportChanges==NoYes::Yes)
    {
        controller.parmReportName(ssrsReportStr(ETG_ClosingSVReport,ReportUOMSerialId));
        controller.parmArgs(_args);
        controller.startOperation();
    }
    else if(ETGACFParameters::find().EnableUATSmallPoints == NoYes::Yes)
    {
        controller.parmReportName(ssrsReportStr(ETG_ClosingSVReport,ReportUOM));
        controller.parmArgs(_args);
        controller.startOperation();
    }
    else
    {
        controller.parmReportName(ssrsReportStr(ETG_ClosingSVReport,Report));
        controller.parmArgs(_args);
        controller.startOperation();
    }
}
//NS, DLT ,11/03/2025  UOM we required along with MT & LBS, KGS AT closing Stock level
